sp_widget.client_script:
function($scope, $http, GlideAjax) {
    var c = this;

    c.$onInit = function() {
        c.loadNavigation();
    };

    c.loadNavigation = function() {
        var ga = new GlideAjax('IDPNavigationEngine');
        ga.addParam('sysparm_name', 'getNavigation');
        ga.getXMLAnswer(function(response) {
            var data = JSON.parse(response);
            c.taxonomies = data.taxonomies;
            c.items = data.items;
            c.rendered = true;
        });
    };

    c.isExpanded = function(taxonomyId) {
        return c.expandedTaxonomies && c.expandedTaxonomies.indexOf(taxonomyId) !== -1;
    };

    c.toggleTaxonomy = function(taxonomyId) {
        if (!c.expandedTaxonomies) {
            c.expandedTaxonomies = [];
        }
        var idx = c.expandedTaxonomies.indexOf(taxonomyId);
        if (idx === -1) {
            c.expandedTaxonomies.push(taxonomyId);
        } else {
            c.expandedTaxonomies.splice(idx, 1);
        }
    };

    c.getTaxonomyItems = function(taxonomyId) {
        return c.items.filter(function(item) {
            return item.taxonomy === taxonomyId;
        });
    };

    c.getItemUrl = function(item) {
        if (item.url) {
            return item.url;
        }
        return '#';
    };
}

sp_widget.css:
.idp-nav-container {
    background: #f8f9fa;
    border-radius: 4px;
    padding: 10px;
}

.idp-nav-taxonomy {
    margin-bottom: 15px;
}

.idp-nav-taxonomy-header {
    cursor: pointer;
    padding: 8px 12px;
    background: #e9ecef;
    border-radius: 4px;
    font-weight: 600;
    display: flex;
    align-items: center;
}

.idp-nav-taxonomy-header:hover {
    background: #dee2e6;
}

.idp-nav-taxonomy-header i {
    margin-right: 8px;
}

.idp-nav-taxonomy-content {
    margin-top: 5px;
}

.idp-nav-item {
    padding: 6px 12px;
    border-radius: 4px;
    transition: background 0.2s;
}

.idp-nav-item:hover {
    background: #e9ecef;
}

.idp-nav-item i {
    margin-right: 8px;
}

.idp-nav-quick-link {
    background: #d4edda;
    border-left: 3px solid #28a745;
}

.idp-nav-quick-link:hover {
    background: #c3e6cb;
}

sp_widget.script:
(function() {
    /* populate the widget data on the server */
})();
